remediationSample:
Avoid paths being concatenated with user inputs.
If this is not possible, validate the arguments using a dedicated method and declare this method as a sanitization method for the quality rule. Example of such methods:

// ----------------------------------------------------------------------------
// 1) Java sample

public static void loadLibrary_secure(String libName) {
  String libPath = getSecureLibraryPath(libName);
  if (libPath != null) {
    System.loadLibrary(libPath);  // ✓ OK
  }
}

private static String getSecureLibraryPath(String libName) {
  final Map<String, String> ALLOWED_LIBS = Map.of(
      "mylib", "/usr/local/libs/mylib.so",
      "otherlib", "/usr/local/libs/otherlib.so"
  );
  String path = ALLOWED_LIBS.get(libName);
  if (path != null) {
    return path;
  } else {
    System.err.println("Invalid library specified.");
    return null;
  }
}


// ----------------------------------------------------------------------------
// 2) C# sample

private static bool LoadLibrary_secure(string libName)
{
  // Validate and get secure the library path
  string securePath = GetSecureLibraryPath(libName);
  if (securePath == null)
  {
    return false;
  }

  if (!System.IO.File.Exists(securePath))
  {
    return false;
  }

  NativeLibrary.Load(securePath); // ✓ OK
  return true;
}

private static string GetSecureLibraryPath(string libName)
{
  Dictionary<string, string> AllowedLibs = new()
  {
    ["mylib"] = "C:\\libs\\mylib.dll",
    ["otherlib"] = "C:\\libs\\otherlib.dll"
  };

  // White-list + absolute path
  if (AllowedLibs.TryGetValue(libName, out var path))
  {
    return path;
  }
  else
  {
    Console.Error.WriteLine("Invalid library specified.");
    return null;
  }
}

